import { Folder, FileText } from "lucide-react";

const files = ["README.md", "tools.css", "contact.css"];

export default function LeftSidebar({
  onOpenFile,
}: {
  onOpenFile: (file: string) => void;
}) {
  return (
    <aside className="border-r border-neutral-800 p-4 text-sm font-mono">
      <div className="mb-4 text-neutral-500">/portfolio</div>

      <div className="space-y-2">
        {["projects", "experience"].map((folder) => (
          <div key={folder} className="flex items-center gap-2">
            <Folder size={14} /> {folder}
          </div>
        ))}
      </div>

      <div className="mt-6 space-y-2">
        {files.map((file) => (
          <button
            key={file}
            onClick={() => onOpenFile(file)}
            className="flex items-center gap-2 text-neutral-400 hover:text-neutral-200"
          >
            <FileText size={14} /> {file}
          </button>
        ))}
      </div>
    </aside>
  );
}
